    etree.SubElement(sp_sso, f"{{{md_ns}}}AssertionConsumerService", attrib={
        "Binding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST",
        "Location": acs_url,
        "index": "0",
        "isDefault": "true",
    })
    if cert:
        key_desc = etree.SubElement(sp_sso, f"{{{md_ns}}}KeyDescriptor", attrib={"use": "signing"})
        key_info = etree.SubElement(key_desc, f"{{{DSIG_NS}}}KeyInfo", nsmap={"ds": DSIG_NS})
        x509_data = etree.SubElement(key_info, f"{{{DSIG_NS}}}X509Data")
        x509_cert = etree.SubElement(x509_data, f"{{{DSIG_NS}}}X509Certificate")
        x509_cert.text = re.sub(r"-----BEGIN CERTIFICATE-----|-----END CERTIFICATE-----|\s+", "", cert).strip()

    xml = etree.tostring(md, xml_declaration=True, encoding="UTF-8", pretty_print=True)
    return HttpResponse(xml, content_type="application/samlmetadata+xml")


